                          setTreeEditMode((prev) => {
                            const next = !prev;
                            if (!next) {
                              setTreeReorderModeNodeId(null);
                              setTreeReorderDraftByParentId({});
                              setTreeReorderDraggingNodeId(null);
                              setTreeReorderSavingParentId(null);
                              setTreeReorderDropTargetSynced(null);
                            }
                            return next;
                          });
